<section class="container section two-col"><div class="panel"><h1>Mi perfil</h1><?php if(!empty($user['photo'])):?><img class="profile-photo" src="<?=Security::e($user['photo'])?>" alt="Fotografía del perfil"><?php endif;?><form method="post" enctype="multipart/form-data" action="index.php?route=profile/update"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><label>Nombre<input name="name" minlength="3" maxlength="100" value="<?=Security::e($user['name'])?>" required></label><label>Correo<input type="email" name="email" maxlength="150" value="<?=Security::e($user['email'])?>" required></label><label>Teléfono<input name="phone" maxlength="20" value="<?=Security::e($user['phone'])?>"></label><label>Fotografía opcional<input type="file" name="photo" accept="image/jpeg,image/png,image/webp"><small>Máximo 2 MB. Formatos JPG, PNG o WEBP.</small></label><button class="btn">Guardar cambios</button></form></div><div class="panel"><h2>Cambiar contraseña</h2><form method="post" action="index.php?route=profile/password"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><label>Nueva contraseña<input type="password" name="password" minlength="6" required></label><label>Confirmar contraseña<input type="password" name="password_confirm" minlength="6" required></label><button class="btn secondary">Actualizar contraseña</button></form></div></section>
